$d = 'D:\Ajit Mane\blog'
ni $d -Force -ItemType Directory | out-null

$t = '<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>{title} — Travel Insurance Info</title><meta name="description" content="{desc}"><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap" rel="stylesheet"><link rel="stylesheet" href="../css/style.css"></head><body><div class="top-bar"><div class="container"><span>&#9432; Informational Website — IRDAI Compliant. We do not sell insurance.</span><a href="https://www.irdai.gov.in" target="_blank" rel="noopener">Visit IRDAI &rarr;</a></div></div><nav class="navbar"><div class="nav-container"><a href="../index.html" class="logo"><span class="logo-icon">&#9992;</span><span class="logo-text">Travel <span>Insurance Info</span></span></a><ul class="nav-links"><li><a href="../index.html">Home</a></li><li><a href="../about.html">About</a></li><li><a href="../blog.html" class="active">Blog</a></li><li><a href="../faq.html">FAQ</a></li><li><a href="../contact.html">Contact</a></li></ul><button class="hamburger" aria-label="Menu"><span></span><span></span><span></span></button></div></nav><section class="blog-article-hero"><div class="container"><span class="blog-article-tag">{tag}</span><h1>{title}</h1><p class="blog-article-meta">Informational Guide &middot; IRDAI Compliant</p></div></section><section><div class="container"><div class="blog-article-body">{body}</div></div></section><div class="blog-nav"><a href="../blog.html">&larr; Back to all articles</a></div><section class="section alt-bg"><div class="container"><div class="disclaimer-box"><span class="warn-icon">&#9888;</span><div><strong>Content Disclaimer:</strong> This article is for informational and educational purposes only. It does not constitute insurance advice, recommendations, or endorsements. Readers should consult a licensed insurance advisor or refer to official IRDAI guidelines for specific insurance decisions. Information is based on publicly available IRDAI regulations and may be subject to change.</div></div></div></section><footer class="footer"><div class="container"><div class="footer-grid"><div class="footer-brand"><div class="logo"><span class="logo-icon">&#9992;</span><span style="color:#fff;">Travel Insurance Info</span></div><p>A free informational resource about travel insurance in India.</p></div><div class="footer-col"><h4>Quick Links</h4><a href="../index.html">Home</a><a href="../about.html">About Us</a><a href="../blog.html">Blog</a><a href="../faq.html">FAQ</a><a href="../contact.html">Contact</a></div><div class="footer-col"><h4>Official Resources</h4><a href="https://www.irdai.gov.in" target="_blank" rel="noopener">IRDAI</a><a href="https://igms.irdai.gov.in" target="_blank" rel="noopener">IRDAI IGMS</a><a href="https://ecoi.co.in" target="_blank" rel="noopener">Insurance Ombudsman</a><a href="https://www.bimabharosa.irdai.gov.in" target="_blank" rel="noopener">Bima Bharosa</a></div><div class="footer-col"><h4>Contact</h4><a href="../contact.html">Get in Touch</a><a href="../contact.html">Grievance Redressal Info</a></div></div><div class="footer-bottom"><span>&copy; 2026 Travel Insurance Info. All rights reserved.</span><span>Informational Website — Not a seller of insurance.</span></div></div></footer><script src="../js/main.js"></script></body></html>'

$a = @(
  @{f='basics.html'; tag='Basics'; title='What is Travel Insurance? A Complete Guide for Indian Travellers'; desc='Everything you need to know about travel insurance.'; body='<h4>What is Travel Insurance?</h4><p>Travel insurance is a specialised insurance policy designed to cover financial losses and medical emergencies that may occur while travelling.</p><p>Travel insurance policies in India are regulated by IRDAI, ensuring standardised practices across all licensed insurers.</p><h4>Why Do Indian Travellers Need Travel Insurance?</h4><ul><li><strong>Medical Emergencies Abroad:</strong> Healthcare costs abroad are significantly higher than in India.</li><li><strong>Mandatory for Visa Applications:</strong> Many countries require proof of travel insurance.</li><li><strong>Trip Cancellation or Interruption:</strong> Reimburses non-refundable expenses.</li><li><strong>Lost or Delayed Baggage:</strong> Compensation for essential purchases.</li><li><strong>Flight Delays:</strong> Covers expenses during prolonged delays.</li><li><strong>Personal Liability:</strong> Protection from legal consequences.</li></ul><h4>Types of Travel Insurance</h4><ul><li><strong>Single-Trip Policy:</strong> For one specific trip.</li><li><strong>Annual Multi-Trip Policy:</strong> For frequent travellers.</li><li><strong>Student Travel Insurance:</strong> For studying abroad.</li><li><strong>Senior Citizen Travel Insurance:</strong> For ages 60+.</li><li><strong>Domestic Travel Insurance:</strong> For travel within India.</li></ul><div class="blog-note"><strong>Important:</strong> All policies must comply with IRDAI guidelines.</div>'}
  @{f='coverage.html'; tag='Coverage'; title='Understanding Travel Insurance Coverage Types'; desc='A detailed breakdown of travel insurance coverage options.'; body='<h4>Individual Travel Insurance</h4><p>Covers a single traveller. Sum insured ranges from USD 50,000 to USD 1,000,000.</p><h4>Family Travel Insurance</h4><p>Covers you, spouse, and children under one plan at lower cost than individual policies.</p><h4>Student Travel Insurance</h4><p>Higher medical coverage (up to USD 250,000+) with tuition fee protection for students abroad.</p><h4>Senior Citizen Travel Insurance</h4><p>Higher limits (up to USD 500,000+) with pre-existing condition options for ages 60+.</p><h4>Domestic Travel Insurance</h4><p>Covers trip cancellation, baggage loss, and delays within India.</p><h4>Annual Multi-Trip Insurance</h4><p>Covers all trips in 12 months. Cost-effective for frequent travellers.</p><div class="blog-note"><strong>Note:</strong> Coverage varies between insurers. For educational purposes only.</div>'}
  @{f='claims.html'; tag='Claims'; title='How to File a Travel Insurance Claim: Step-by-Step Guide'; desc='Learn the claim procedure, required documents, and tips for a smooth process.'; body='<h4>Understanding the Claim Process</h4><p>Under IRDAI guidelines, insurers must have a transparent claim settlement process.</p><h4>Step 1: Notify the Insurer</h4><p>Notify within 24-48 hours. For medical emergencies, the assistance team guides you to network hospitals.</p><h4>Step 2: Gather Documents</h4><p><strong>Medical:</strong> Bills, discharge summary, prescriptions, passport copies.<br><strong>Baggage:</strong> PIR report, boarding passes, baggage tags.<br><strong>Cancellation:</strong> Booking documents, cancellation invoices, evidence.<br><strong>Delay:</strong> Boarding passes, delay certificate, receipts.</p><h4>Step 3: Submit</h4><p>Submit online, via email, or post. Keep copies and note the claim reference number.</p><h4>Step 4: Settlement</h4><p>30 days standard (45 days if investigation needed). Rejected claims include a written explanation.</p><div class="blog-note"><strong>IRDAI:</strong> Escalate to grievance officer, IGMS (igms.irdai.gov.in), then Ombudsman.</div>'}
  @{f='regulations.html'; tag='Regulations'; title='IRDAI Guidelines for Travel Insurance: What You Must Know'; desc='Key IRDAI regulations governing travel insurance in India.'; body='<h4>Role of IRDAI</h4><p>IRDAI regulates all travel insurance products sold in India to protect policyholder interests.</p><h4>Key Regulations</h4><ul><li><strong>Standardisation:</strong> Products approved by IRDAI before launch.</li><li><strong>Claim Timelines:</strong> 30 days standard, 45 days for investigation.</li><li><strong>Free Look Period:</strong> 15 days to review and return the policy.</li><li><strong>Disclosure:</strong> Terms and exclusions must be clearly stated.</li><li><strong>Portability:</strong> Right to switch insurers.</li><li><strong>Grievance Redressal:</strong> Escalation path to IGMS and Ombudsman.</li></ul><h4>Grievance Process</h4><ul><li>Level 1: Insurer grievance officer</li><li>Level 2: IGMS at igms.irdai.gov.in</li><li>Level 3: Insurance Ombudsman at ecoi.co.in</li><li>Level 4: Bima Bharosa at bimabharosa.irdai.gov.in</li></ul><div class="blog-note"><strong>Remember:</strong> IRDAI regulations protect your interests as a policyholder.</div>'}
  @{f='health.html'; tag='Health'; title='Medical Coverage in Travel Insurance: What&rsquo;s Included?'; desc='Understanding medical benefits of travel insurance.'; body='<h4>Why Medical Coverage Matters</h4><p>Medical emergencies are the top reason for claims. Healthcare costs abroad are far higher than in India.</p><h4>What&rsquo;s Included</h4><ul><li><strong>Emergency Hospitalisation:</strong> Inpatient treatment, surgery, ICU.</li><li><strong>Outpatient Treatment:</strong> Doctor consultations, tests, medications.</li><li><strong>Emergency Dental:</strong> Urgent procedures from accidents.</li><li><strong>Medical Evacuation:</strong> Transport to adequate facility or repatriation.</li><li><strong>Repatriation of Remains:</strong> Transport back to India.</li></ul><h4>Coverage Limits</h4><ul><li>Basic: USD 50,000-100,000</li><li>Standard: USD 200,000-500,000</li><li>Comprehensive: USD 500,000-1,000,000+</li></ul><h4>Common Exclusions</h4><ul><li>Pre-existing conditions</li><li>Alcohol-related incidents</li><li>Adventure sports (unless covered)</li><li>Routine check-ups</li></ul><div class="blog-note"><strong>Tip:</strong> Check policy wording for specific inclusions and exclusions.</div>'}
  @{f='seniors.html'; tag='Seniors'; title='Travel Insurance for Senior Citizens: Key Considerations'; desc='Special considerations for senior travellers aged 60+.'; body='<h4>Unique Needs for Seniors</h4><p>Senior travellers aged 60+ have unique health considerations requiring specialised travel insurance plans.</p><h4>Key Features</h4><ul><li><strong>Higher Medical Limits:</strong> Up to USD 500,000+ for senior plans.</li><li><strong>Pre-Existing Conditions:</strong> May cover stable conditions like diabetes and hypertension at additional premium.</li><li><strong>Medical Evacuation:</strong> Enhanced coverage for emergencies.</li><li><strong>Companion Coverage:</strong> Some policies cover a companion if hospitalised.</li><li><strong>24/7 Assistance:</strong> Multilingual helpline for coordinating care.</li></ul><h4>Age Limits</h4><p>Senior plans may cover up to age 80-85, while standard policies max out at 65-70. Premiums are higher due to increased risk.</p><h4>Tips</h4><ul><li>Disclose all pre-existing conditions accurately.</li><li>Carry sufficient prescription medications.</li><li>Keep emergency contacts accessible.</li><li>Choose adequate coverage for your destination.</li></ul><div class="blog-note"><strong>Important:</strong> Terms vary between insurers. For educational purposes only.</div>'}
  @{f='exclusions.html'; tag='Exclusions'; title='Common Exclusions in Travel Insurance Policies'; desc='Understanding what is not covered by travel insurance.'; body='<h4>Why Exclusions Exist</h4><p>Exclusions help insurers manage risk and keep premiums affordable. Every policy must list exclusions clearly per IRDAI guidelines.</p><h4>Common Exclusions</h4><ul><li><strong>Pre-Existing Conditions:</strong> Not covered unless specifically added.</li><li><strong>Adventure Sports:</strong> Bungee, skydiving, scuba, etc. (may be added on).</li><li><strong>Alcohol/Drugs:</strong> Expenses from intoxication are excluded.</li><li><strong>War/Terrorism:</strong> Losses from war, terrorism, civil unrest.</li><li><strong>Self-Inflicted Injuries:</strong> Intentional self-harm or suicide.</li><li><strong>Pregnancy:</strong> Routine childbirth not covered.</li><li><strong>Non-Disclosure:</strong> Claims rejected if material facts hidden.</li></ul><h4>Avoid Surprises</h4><ul><li>Read the exclusions section carefully.</li><li>Check if adventure sports need an add-on.</li><li>Disclose all information truthfully.</li></ul><div class="blog-note"><strong>Disclaimer:</strong> Exclusions vary by policy. Always refer to specific policy wording.</div>'}
  @{f='students.html'; tag='Students'; title='Student Travel Insurance: Coverage for Studying Abroad'; desc='Specialised insurance for Indian students going abroad.'; body='<h4>Why Students Need Specialised Insurance</h4><p>Student travel insurance covers extended study durations, higher medical requirements, tuition fee loss, and more.</p><h4>Key Coverage Areas</h4><ul><li><strong>Medical Coverage:</strong> Hospitalisation, outpatient care, prescriptions (min. USD 250,000 often required).</li><li><strong>Tuition Fee Protection:</strong> Refund if unable to complete semester due to medical emergency.</li><li><strong>Parent Emergency Travel:</strong> Covers travel for parents to visit hospitalised student.</li><li><strong>Study Interruption:</strong> Compensation for interrupted studies.</li><li><strong>Personal Accident:</strong> Cover for accidental death or disability.</li><li><strong>Baggage:</strong> Loss or damage to laptops, books, etc.</li></ul><h4>Countries Requiring Insurance</h4><ul><li><strong>USA:</strong> Most universities require health insurance.</li><li><strong>Australia:</strong> OSHC mandatory for student visa.</li><li><strong>UK:</strong> IHS paid with visa application.</li><li><strong>Canada/Europe:</strong> Often required for visa.</li></ul><div class="blog-note"><strong>Note:</strong> Verify requirements with your university and embassy.</div>'}
  @{f='covid.html'; tag='COVID-19'; title='Does Travel Insurance Cover COVID-19? What You Should Know'; desc='Understanding COVID-19 coverage in travel insurance policies.'; body='<h4>COVID-19 and Travel Insurance</h4><p>Since 2020, many Indian insurers have revised policies to address COVID-19 scenarios following IRDAI guidance.</p><h4>Typically Covered</h4><ul><li><strong>Medical Treatment:</strong> Hospitalisation and treatment if you contract COVID-19 during travel.</li><li><strong>Trip Cancellation:</strong> If you test positive before departure.</li><li><strong>Quarantine Expenses:</strong> Accommodation and meals if required to quarantine.</li><li><strong>Medical Evacuation:</strong> Transfer to adequate facility if needed.</li></ul><h4>Typically Not Covered</h4><ul><li>Travel against government advisories.</li><li>Testing solely for travel purposes.</li><li>Vaccine-related claims unless specified.</li></ul><div class="blog-note"><strong>Note:</strong> COVID-19 coverage is evolving. Check the latest policy terms before travelling.</div>'}
  @{f='rights.html'; tag='Rights'; title='Your Rights as a Travel Insurance Policyholder Under IRDAI'; desc='Know your rights as a policyholder under IRDAI.'; body='<h4>IRDAI&rsquo;s Mandate</h4><p>IRDAI protects the interests of insurance policyholders and regulates the insurance industry.</p><h4>Your Key Rights</h4><ul><li><strong>Free Look Period:</strong> 15 days to review and return the policy.</li><li><strong>Fair Claim Settlement:</strong> 30 days standard, 45 days for investigation.</li><li><strong>Clear Information:</strong> Policy wordings in simple language.</li><li><strong>Grievance Redressal:</strong> Escalate to IGMS and Ombudsman.</li><li><strong>Portability:</strong> Switch insurers while maintaining benefits.</li><li><strong>Nomination:</strong> Nominate a beneficiary for claim benefits.</li></ul><h4>If Your Rights Are Violated</h4><ul><li>Document all communication.</li><li>File complaint with insurer grievance officer.</li><li>Escalate to IGMS at igms.irdai.gov.in.</li><li>Approach Insurance Ombudsman at ecoi.co.in.</li><li>Contact Bima Bharosa at bimabharosa.irdai.gov.in.</li></ul><div class="blog-note"><strong>Empower Yourself:</strong> Know your rights for fair treatment from insurers.</div>'}
  @{f='providers.html'; tag='Providers'; title='Travel Insurance Providers in India: Registered Companies Offering Travel Insurance'; desc='List of IRDAI-registered insurance companies offering travel insurance.'; body='<div class="blog-note"><strong>Disclaimer:</strong> This is a reference list only. We do not endorse or recommend any insurer.</div><h4>Public Sector Insurers</h4><ul><li><strong>New India Assurance</strong> — newindia.co.in</li><li><strong>Oriental Insurance</strong> — orientalinsurance.org.in</li><li><strong>United India Insurance</strong> — uiic.co.in</li><li><strong>National Insurance</strong> — nationalinsuranceindia.com</li></ul><h4>Private Sector Insurers</h4><ul><li><strong>Bajaj Allianz</strong> — bajajallianz.com</li><li><strong>Chola MS</strong> — cholainsurance.com</li><li><strong>Digit Insurance</strong> — godigit.com</li><li><strong>Future Generali</strong> — futuregenerali.in</li><li><strong>HDFC ERGO</strong> — hdfcergo.com</li><li><strong>ICICI Lombard</strong> — icicilombard.com</li><li><strong>IFFCO Tokio</strong> — iffkotokio.com</li><li><strong>Kotak Mahindra</strong> — kotakgeneral.com</li><li><strong>Liberty General</strong> — libertygeneral.in</li><li><strong>Reliance General</strong> — reliancegeneral.co.in</li><li><strong>Royal Sundaram</strong> — royalsundaram.in</li><li><strong>SBI General</strong> — sbigeneral.in</li><li><strong>Tata AIG</strong> — tataaig.com</li></ul><h4>Standalone Health Insurers</h4><ul><li><strong>Care Health</strong> — careinsurance.com</li><li><strong>Star Health</strong> — starhealth.in</li><li><strong>Aditya Birla Health</strong> — adityabirlahealth.com</li><li><strong>ManipalCigna</strong> — manipalcigna.com</li><li><strong>Niva Bupa</strong> — nivabupa.com</li></ul><h4>Intermediaries</h4><p><a href="https://btwimf.com/" target="_blank" rel="noopener">btwimf.com</a> is a <strong>Multi-Insurer Distribution Platform</strong>. Reference example only.</p><h4>Verification</h4><p>Verify IRDAI registration at irdai.gov.in.</p><div class="blog-note"><strong>Note:</strong> This is not an exhaustive list.</div>'}
)

ForEach ($a in $articles) {
  $html = $t -replace '{title}', $a.title -replace '{desc}', $a.desc -replace '{tag}', $a.tag -replace '{body}', $a.body
  Set-Content -LiteralPath "$d\$($a.f)" -Value $html -NoNewline
  Write-Output "Created blog/$($a.f)"
}
